import React from 'react'
import { Link } from 'react-router-dom';

const ContactForm = () => {
  return (
    <section id="contact-area">
    <div className="container">
      <div className="row">
        <div className="col-lg-12">
          <div className="contact-relative">
            <div className="contact-wh-bg">
              <div className="row">
                
                <div className="col-lg-9 offset-lg-3">
                  <div className="" id="margin-left-per">
                    <h2>Get in Touch</h2>
                  <form action="get" id="contact-form" className="forms">
                    <div className="row">
                        <div className="col-lg-12">
                            <div className="input_type">
                                <div className="input-group">
                                    <span className="input-group-addon csaddn"><i className="fa fa-user"></i></span>
                                    <input id="name" className="form-control" type="text" placeholder="Name" />
                                </div>
                            </div>
                        </div>
                        
                    </div>
                    <div className="row">
                      <div className="col-lg-12">
                        <div className="input_type">
                            <div className="input-group">
                                <span className="input-group-addon csaddn"><i className="fa fa-phone"></i></span>
                                <input id="email" className="form-control" type="email" placeholder="Phone" />
                            </div>
                        </div>
                      </div>
                    
                    </div>
                    <div className="row">
                      <div className="col-lg-12">
                        <div className="input_type">
                            <div className="input-group">
                                <span className="input-group-addon csaddn"><i className="fa fa-at"></i></span>
                                <input id="phone" className="form-control" type="text" placeholder="Email" />
                            </div>
                        </div>
                    </div>
                      <div className="col-lg-6 col-md-6 col-sm-6 col-xs-12">
                          <div className="input_type">
                              <div className="input-group">
                                  <span className="input-group-addon csaddn"><i className="fa fa-clock"></i></span>
                                  <input id="phone" className="form-control" type="text" placeholder="00 00 AM" />
                              </div>
                          </div>
                      </div>
                      <div className="col-lg-6 col-md-6 col-sm-6 col-xs-12">
                          <div className="input_type">
                              <div className="input-group">
                                  <span className="input-group-addon csaddn"><i className="fa-solid fa-calendar"></i></span>
                                  <input id="web" className="form-control" type="text" placeholder="mm  dd  yyyy" />
                              </div>
                          </div>
                      </div>
                  </div>
                    <div className="row">
                        <div className="col-lg-12">
                            <div className="input_type">
                                <div className="input-group">
                                    <span className="input-group-addon csaddn"><i className="fa-solid fa-file-lines"></i></span>
                                    <input id="phone" className="form-control" type="text" placeholder="Subject" />
                                </div>
                            </div>
                        </div>
                        
                    </div>
                    <div className="row">
                        <div className="col-lg-12 col-md-12 col-sm-12 col-xs-12">
                            <div className="input_type">
                                <div className="input-group">
                                  <span className="input-group-addon csaddn"><i className="fa-solid fa-envelope"></i></span>
                                  <textarea name="Message" id="Message" placeholder="Message" className="form-control"></textarea>
                              </div>
                                
                            </div>
                            <div className="submit_button">
                                <Link to={'/'} className="btn btn-contact-submit" role="button">Submit Form</Link>
                            </div>
                        </div>
                    </div>
                </form>
                  </div>
                </div>
              </div>
            </div>
            <div className="row">
              <div className="col-lg-5">
                <div className="contact-ylw-bg">
                  <h2>CONTACT <br/> INFORMATION</h2>
                  <h6>4804 Laurel Canyon Blvd Valley Village, CA 91607</h6>
                  <ul className="contact-details">
                    <li><i className="fa-solid fa-phone"></i>(818) 287-0057</li>
                    <li><i className="fa-solid fa-mobile"></i>800-499-8128</li>
                    <li><i className="fa-solid fa-at"></i>book@limousine4hire.net</li>
                    <li><i className="fa-solid fa-clock"></i>24/7 Dispatch Service</li>
                    <li><i className="fa-solid fa-clock"></i>Sales Office: Monday-Friday 9am-6pm PT</li>
                  </ul>
                  <h3>SOCIAL MEDIA</h3>
                  <ul className="social-contact">
                    <li><Link to={'/'}><i className="fa-brands fa-facebook"></i></Link></li>
                    <li><Link to={'/'}><i className="fa-brands fa-twitter"></i></Link></li>
                    <li><Link to={'/'}><i className="fa-brands fa-linkedin-in"></i></Link></li>
                    <li><Link to={'/'}><i className="fa-brands fa-youtube"></i></Link></li>
                    <li><Link to={'/'}><i className="fa-brands fa-instagram"></i></Link></li>
                    <li><Link to={'/'}><i className="fa-brands fa-pinterest"></i></Link></li>
                  </ul>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
</section>
  )
}

export default ContactForm