import React from 'react'
import FooterLogo from '../../assets/img/footer-logo.png';
import Slider from "react-slick";
import "slick-carousel/slick/slick.css"; 
import "slick-carousel/slick/slick-theme.css";
import Partner from '../../assets/img/partner.jpg'
import { Link } from 'react-router-dom';

const Footer = () => {

  const settings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    arrows:false
  };

  
  return (
    <footer id="main-footer">
    <div className="container">
      <div className="row">
        <div className="col-lg-3">
          <img src={FooterLogo} alt="" />
          <div className="footer-logo-text">
            <p>Schedule your private car service today for stress-free travel tomorrow.</p>
          </div>
        </div>
        <div className="col-lg-3 padding-left-right">
          <h4>Partners</h4>
          <Slider {...settings} >
            <div className="item"><img src={Partner} alt="" /></div>
            <div className="item"><img src={Partner} alt="" /></div>
            <div className="item"><img src={Partner} alt="" /></div>
            <div className="item"><img src={Partner} alt="" /></div>
            <div className="item"><img src={Partner} alt="" /></div>
            <div className="item"><img src={Partner} alt="" /></div>
            </Slider>
        <p>Hotel Westlake Village California </p>
        </div>
        <div className="col-lg-3">
          <h4>Book A Ride</h4>
          <ul id="footer-nav">
            <li><Link to={'/'}>Airport Car Services</Link></li>
            <li><Link to={'/'}>City Tours</Link></li>
            <li><Link to={'/'}>Hourly</Link></li>
          
          </ul>
        </div>
        <div className="col-lg-3">
          <h4>Contact Us</h4>
          <div className="row">
            <div className="col-lg-12">
              <span className="footer-telephone"><i className="fa-solid fa-phone"></i><a href="tel:(800) 499-8128">(800) 499-8128</a></span>
            </div>
          </div>
          <div className="row">
            <div className="col-lg-12">
              <span className="footer-email"><i className="fa-solid fa-at"></i><a href="mailto:book@limousine4hire.net">Book A Ride</a></span>
            </div>
          </div>
          <div className="row">
            <div className="col-lg-8">
              <ul id="social-icon">
                <li><Link to={'/'} className="hvr-bounce-in"><i className="fa-brands fa-facebook"></i></Link></li>
                <li><Link to={'/'} className="hvr-bounce-in"><i className="fa-brands fa-twitter"></i></Link></li>
                <li><Link to={'/'} className="hvr-bounce-in"><i className="fa-brands fa-linkedin-in"></i></Link></li>
                <li><Link to={'/'} className="hvr-bounce-in"><i className="fa-brands fa-youtube"></i></Link></li>
                <li><Link to={'/'} className="hvr-bounce-in"><i className="fa-brands fa-instagram"></i></Link></li>
                <li><Link to={'/'} className="hvr-bounce-in"><i className="fa-brands fa-pinterest"></i></Link></li>
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  </footer>
  )
}

export default Footer