import React from 'react'
import Slider from "react-slick";
import "slick-carousel/slick/slick.css"; 
import "slick-carousel/slick/slick-theme.css";

const Testimonial = () => {

  const settings = {
    dots: false,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    arrows:true
  };


  return (
    <section id="testimonial">

    <Slider {...settings}>

      <div className="item">
            <div className="section-relative">
              <div className="section-bg-1">
              
              </div>
              <div className="container padding-bottom-huge">
                <div className="row">
                  <div className="col-lg-6">
                    
                      <div className="row">
                        <div className="col-lg-12">
                          <h2>Full-Service solutions for all  private transportation needs</h2>
                        </div>
                      </div>
                      <div className="row">
                        <div className="col-lg-12">
                          <p>We do it all from chauffer to corporate travel to city tours and more.</p>
                        </div>
                      </div>
                    
                  </div>
                  <div className="col-lg-6">
                      
                  </div>
                </div>
              </div>
          </div>
      </div>

              <div className="item">
                <div className="section-relative">
                  <div className="section-bg-2">
                  
                  </div>
                  <div className="container padding-bottom-huge">
                    <div className="row">
                      <div className="col-lg-6">
                        
                          <div className="row">
                            <div className="col-lg-12">
                              <h2>Private City Tours</h2>
                            </div>
                          </div>
                          <div className="row">
                            <div className="col-lg-12">
                              <p>Los Angeles, Orange County, San Diego, Santa Barbara</p>
                            </div>
                          </div>
                        
                      </div>
                      <div className="col-lg-6">
                          
                      </div>
                    </div>
                  </div>
              </div>
          </div>

          <div className="item">
            <div className="section-relative">
              <div className="section-bg-3">
              
              </div>
              <div className="container padding-bottom-huge">
                <div className="row">
                  <div className="col-lg-6">
                    
                      <div className="row">
                        <div className="col-lg-12">
                          <h2>Simple Online Reservation System</h2>
                        </div>
                      </div>
                      <div className="row">
                        <div className="col-lg-12">
                          <p>Schedule your private car service in a few short clicks.</p>
                        </div>
                      </div>
                    
                  </div>
                  <div className="col-lg-6">
                      
                  </div>
                </div>
              </div>
          </div>
        </div>

        <div className="item">
          <div className="section-relative">
            <div className="section-bg-4">
            
            </div>
            <div className="container padding-bottom-huge">
              <div className="row">
                <div className="col-lg-6">
                  
                    <div className="row">
                      <div className="col-lg-12">
                        <h2>Private Car Services with VIP Treatment!</h2>
                      </div>
                    </div>
                    <div className="row">
                      <div className="col-lg-12">
                        <p>Get the VIP experience whenever and wherever you travel.</p>
                      </div>
                    </div>
                  
                </div>
                <div className="col-lg-6">
                    
                </div>
              </div>
            </div>
        </div>
      </div>
  </Slider>
  </section>
  )
}

export default Testimonial