import React from 'react'
import { Link } from 'react-router-dom';

const CallToAction = () => {
  return (
    <section id="call-to-action">
    <div className="container">
      <div className="row">
        <div className="col-lg-6">
          <h2>Get private car services with <br /> VIP treatment!</h2>
          <p>Welcome to Limousine 4 Hire car services. We offer the perfect blend <br /> of elegance and style to meet your ground transportation needs in the <br /> greater Los Angeles, Orange County, San Diego, and Santa Barbara <br /> areas. Looking for private, individual car services or group <br/> transportation? Booking a ride is a fast and easy. Get premium and <br /> elegant car services available at your fingertips 24/7.</p>
          <Link to={'/'} className="btn btn-main hvr-icon-forward" role="button">Book Now <img className="hvr-icon" src="img/Arrow - Right Circle.svg" alt="" /></Link>
        </div>
      </div>
    </div>
  </section>
  )
}

export default CallToAction