import React from 'react'

const ContactHeader = () => {
  return (
    <section id="page-titles">
    <div className="airport-service-overlay">

    </div>
    <div className="container">
      <div className="row">
        <div className="col-lg-12">
          <h2 id="contact-h">Contact</h2>
          <div className="col-lg-5">
            <div className="contact-overlay">
              <p>When you call us, we answer the phone. You never get an answering machine.</p>
              <p>One of our trained dispatchers will always answer the phone and be able to handle your call
                24 hours a day, 7 days a week, 365 days a year</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  </section>
  )
}

export default ContactHeader