import React from 'react'
import { Link } from 'react-router-dom';

const BannerArea = () => {
  return (
    <section id="banner-area">
    <div className="overlay">

    </div>
    <div className="container">
      <div className="row">
        <div className="col-lg-6">
          <h2 className="huge-margin">The best private car service in California!</h2>
          
            <span className="elegant"><i className="fa-solid fa-square-check"></i>Elegant curbside car service when and where you need it</span>
          
          <h2 className="right-align-h">24/7</h2>
        </div>
        <div className="col-lg-6">
          
              <h3>Book a ride today!</h3>
              <div className="call-action-group hvr-bounce-in">
                <div className="row">
                  <div className="col-lg-12">
                    <h4><i className="fa-solid fa-plane"></i>Airport Car Service</h4>
                  </div>
                </div>
                <div className="row">
                  <div className="col-lg-8">Advanced reservations make your travel plans to and from the airport easy and stress-free.</div>
                  <div className="col-lg-4"><Link to={'/'} className="btn btn-main hvr-icon-forward" role="button">Book Now <img className="hvr-icon" src="img/Arrow - Right Circle.svg" alt="" /></Link></div>
                </div>
              </div>
              <div className="call-action-group hvr-bounce-in">
                <div className="row">
                  <div className="col-lg-12">
                    <h4><i className="fa-solid fa-city"></i>City Tours</h4>
                  </div>
                </div>
                <div className="row">
                  <div className="col-lg-8">No surprises with our upfront pricing. Get rides to and from anywhere.</div>
                  <div className="col-lg-4"><Link to={'/'} className="btn btn-main hvr-icon-forward" role="button">Book Now <img className="hvr-icon" src="img/Arrow - Right Circle.svg" alt="" /></Link></div>
                </div>
              </div>
              <div className="call-action-group">
                <div className="row">
                  <div className="col-lg-12">
                    <h4><i className="fa-solid fa-clock"></i>Hourly</h4>
                  </div>
                </div>
                <div className="row">
                  <div className="col-lg-8">We are available when you need us, for as long as it takes.</div>
                  <div className="col-lg-4"><Link to={'/'} className="btn btn-main hvr-icon-forward" role="button">Book Now <img className="hvr-icon" src="img/Arrow - Right Circle.svg" alt="" /></Link></div>
                </div>
              </div>

              <div className="row">
                <div className="col-lg-6">
                  <button className="btn btn-edit hvr-icon-pulse">Edit Reservation<i className="fa-solid fa-pen hvr-icon"></i></button>
                </div>
                <div className="col-lg-6">
                  <button className="btn btn-cancel hvr-icon-pulse">CANCEL Reservation<i className="fa-solid fa-xmark hvr-icon"></i></button>
                </div>
              </div>
            
        </div>
      </div>
    </div>
    
  </section>
  )
}

export default BannerArea