import React, {useState} from 'react'
import Logo from '../../assets/img/logo.png';
import { Link } from 'react-router-dom';
import {
  Collapse,
  Navbar,
  NavbarToggler,
  Nav,
  NavItem,
  UncontrolledDropdown,
  DropdownToggle,
  DropdownMenu,
  DropdownItem,
} from 'reactstrap';
import Chauffeur from '../../assets/img/nav-chauffeur.svg';
import Wedding from '../../assets/img/nav-weeding.svg'
import Leisure from '../../assets/img/nav-leisure.svg';
import Video from '../../assets/img/nav-video.svg'
import Keys from '../../assets/img/nav-keys.svg'

const Header = () => {

  const [isOpen, setIsOpen] = useState(false);

  const toggle = () => setIsOpen(!isOpen);

  return (
    <header id="main-header">
    <nav className="navbar navbar-expand-lg main-nav-bar navbar-dark">
      <div id="no-flex" className="container">
        <div className="row">
            <div className="col-lg-3 col-xs-4">
              <Link className="navbar-brand" to={'/'}>
                <img src={Logo} alt="" />
              </Link>
              <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#main-navbar" aria-controls="main-navbar" aria-expanded="false" aria-label="Toggle navigation">
                <span className="navbar-toggler-icon"></span>
              </button>
            </div>

            <div className="col-lg-6 col-xs-4">
            <Navbar id="main-navbar">
              <NavbarToggler onClick={toggle} />
              <Collapse isOpen={isOpen} navbar>
                <Nav className="me-auto" navbar>
                  <NavItem>
                    <Link className="nav-link active" aria-current="page" to={'/'}>Book A Ride</Link>
                  </NavItem>
                  <UncontrolledDropdown nav inNavbar>
                    <DropdownToggle nav caret>
                      Services
                    </DropdownToggle>
                    <DropdownMenu right>
                      <DropdownItem><Link to={'/airport-service'}><i className="fa-solid fa-plane"></i> Airport Car Service</Link></DropdownItem>
                      <DropdownItem><Link to={'/chauffeur-service'}><img src={Chauffeur} alt="" style={{width: '7%'}} /> Chauffer Service</Link></DropdownItem>
                      <DropdownItem><Link to={'/city-tours'}><i className="fa-solid fa-city"></i> City Tours</Link></DropdownItem>
                      <DropdownItem><Link to={'/weddings'}><img src={Wedding} alt="" style={{width: '7%'}} /> Weddings and Events</Link></DropdownItem>
                      <DropdownItem><Link to={'/corporate-transportation'}><i className="fa-solid fa-user-tie"></i> Corporate Transportation</Link></DropdownItem>
                      <DropdownItem><Link to={'/leisure-transportation'}><img src={Leisure} alt="" style={{width: '7%'}} /> Leisure Transportation</Link></DropdownItem>
                      <DropdownItem><Link to={'/group-transportation'}><i className="fa-solid fa-users"></i> Group Transportation</Link></DropdownItem>
                      <DropdownItem><Link to={'/entertainment'}><img src={Video} alt="" style={{width: '7%'}} /> Entertainment and Production</Link></DropdownItem>
                      <DropdownItem><Link to={'/valet-service'}><img src={Keys} alt="" style={{width: '7%'}} /> Valet Service</Link></DropdownItem>
                    </DropdownMenu>
                  </UncontrolledDropdown>
                  <NavItem>
                    <Link className="nav-link" aria-current="page" to={'/rates'}>Rates</Link>
                  </NavItem>
                  <NavItem>
                    <Link className="nav-link" aria-current="page" to={'/blog'}>Blog</Link>
                  </NavItem>
                  <NavItem>
                  <Link className="nav-link" aria-current="page" to={'/contact'}>Contact Us</Link>
                  </NavItem>
                </Nav>
                
              </Collapse>
            </Navbar>
            </div>
            <div className="col-lg-3 col-xs-4">
              <div className="row">
                <div className="col-lg-12">
                  <div className="telephone">
                    <i className="fa-solid fa-phone"></i> <span><a href="tel:(800) 499-8128">(800) 499-8128</a></span>
                  </div>
                </div>
              </div>
              <div className="row">
                <div className="col-lg-12">
                  <div className="login-menu">
                    <ul className="login-reg">
                      <li><Link to={'/'}><i className="fa-solid fa-user"></i>Login</Link></li>
                      <li><Link to={'/'}>Register</Link></li>
                    </ul>
                  </div>
                </div>
              </div>
            </div>
        </div>
      </div>
    </nav>
  </header>
  )
}

export default Header